const H2=({children,it,sz="clamp(1.9rem,4.5vw,3rem)",style:sx={}})=><h2 style={{fontFamily:"var(--serif)",fontSize:sz,fontWeight:500,lineHeight:1.15,color:"var(--black)",fontStyle:it?"italic":"normal",...sx}}>{children}</h2>;
