function Btn({children,nude,outline,onClick,href,full,style:sx={}}){
  const b={display:"inline-flex",alignItems:"center",gap:8,padding:"15px 34px",fontSize:".7rem",fontWeight:600,letterSpacing:".18em",textTransform:"uppercase",border:"none",borderRadius:0,fontFamily:"var(--sans)",transition:"all .3s",...(full?{width:"100%",justifyContent:"center"}:{}),...sx};
  const styles=outline?{...b,background:"transparent",color:"var(--black)",border:"1px solid var(--black)"}:{...b,background:nude?"var(--nude)":"var(--black)",color:"var(--white)"};
  if(href)return<a href={href} target="_blank" rel="noopener" style={styles} onClick={onClick}>{children}</a>;
  return<button onClick={onClick} style={styles}>{children}</button>;
}

