// ─── BSPORT WIDGET ───
function BsportWidget({type="calendar",h=650}){
  const iframeRef=useRef(null);
  const wt=type==="calendar"?"calendar":"subscription";
  useEffect(()=>{
    const iframe=iframeRef.current;if(!iframe)return;
    const mid=wt==="calendar"?"bsport-widget-805329":"bsport-widget-12349";
    const cfg=wt==="calendar"?`{calendar:{todayOnly:false,cardMode:null}}`:`{subscription:{}}`;
    iframe.srcdoc=`<!DOCTYPE html><html><head><meta charset="UTF-8"/><meta name="viewport" content="width=device-width,initial-scale=1.0"/><style>body{margin:0;padding:0;font-family:Helvetica,Arial,sans-serif;background:#F5F2EE}#${mid}{min-height:${h}px}</style></head><body><div id="${mid}"></div><script>!function(b,s,p){typeof window.BsportWidget==="undefined"&&!document.getElementById("bsport-widget-cdn")&&!function(){m=b.createElement(s),m.id="bsport-widget-cdn",m.src=p,b.getElementsByTagName("head")[0].appendChild(m)}()}(document,"script","https://cdn.bsport.io/scripts/widget.js");function MB(c,r){if(r>50)return;if(!window.BsportWidget)return setTimeout(()=>MB(c,r+1),100*r||1);BsportWidget.mount(c)}MB({parentElement:"${mid}",companyId:5566,franchiseId:null,dialogMode:1,widgetType:"${wt}",showFab:false,fullScreenPopup:false,styles:undefined,config:${cfg}});function rh(){const h=Math.max(document.body.scrollHeight,document.documentElement.scrollHeight);parent.postMessage({type:'bsport-resize',height:h},'*')}new MutationObserver(rh).observe(document.body,{childList:true,subtree:true,attributes:true});setInterval(rh,1000);<\/script></body></html>`;
    const fn=e=>{if(e.data&&e.data.type==='bsport-resize'&&iframeRef.current)iframeRef.current.style.height=Math.max(e.data.height,h)+"px"};
    window.addEventListener("message",fn);return()=>window.removeEventListener("message",fn);
  },[wt,h]);
  return<iframe ref={iframeRef} style={{width:"100%",minHeight:h,border:"none",background:"var(--white)",borderRadius:4,display:"block"}} title={`BSport ${wt}`}/>;
}

