// ABOUT (with FAQ section)
// ════════════════════════════════════════
function About(){
  const[openFaq,setOpenFaq]=useState(null);
  const faqs=[
    {q:"What should I wear to class?",a:"Comfortable, form-fitting athletic wear. Grip socks are required for all classes."},
    {q:"Do I need to bring my own mat?",a:"We recommend bringing your own mat, but premium STAKT mats are available to rent in-studio."},
    {q:"Is Studio Zo beginner-friendly?",a:"Absolutely. All classes are designed for every level, with guided instruction and modifications throughout."},
    {q:"What is infrared heat?",a:"Infrared heat warms your body from within rather than heating the air around you. It supports deeper movement, improved recovery, and a more effective workout — without overwhelming heat."},
    {q:"How does Zo Kids work?",a:"Reserve your child's spot through BSport when booking your class. Zo Kids is available during select class times for children. It's included with the Unlimited + Zo Kids membership, or $10 per drop-in."},
    {q:"What's your cancellation policy?",a:"Changes or cancellations can be made up to 12 hours before class. Late cancellations or no-shows may result in a fee or class deduction."},
    {q:"Where is Studio Zo located?",a:"We're located at 7708 Gunston Plaza, Lorton, VA 22079."},
    {q:"When does Studio Zo open?",a:"Founding memberships are available now. Follow us on social media for updates on our official opening date."},
  ];

  return<div className="page-in">
    <section id="story" style={{padding:"80px 24px 60px",textAlign:"center",background:"var(--ivory)"}}>
      <Rv><Eye>Our Story</Eye><H2>About <span style={{fontStyle:"italic",color:"var(--nude)"}}>Studio Zo</span></H2><P style={{maxWidth:520,margin:"14px auto 0"}}>More than a studio — a sanctuary for movement, community, and transformation.</P></Rv>
    </section>

    <section style={{padding:"0 24px 80px",background:"var(--ivory)"}}>
      <div style={{maxWidth:780,margin:"0 auto"}}>
        <Rv><div style={{fontSize:".95rem",fontWeight:400,color:"var(--text)",lineHeight:1.95,textAlign:"center"}}>
          <p style={{marginBottom:20}}>Studio Zo is Northern Virginia's first infrared heated mat Pilates studio, created for modern movement, strength, and balance.</p>
          <p style={{marginBottom:20}}>We combine fitness, mindfulness, and community within a thoughtfully designed, elevated space. Our infrared heated studio enhances every session, while our dedicated Zo Kids room allows parents to show up fully—without having to choose between fitness and family.</p>
          <p>More than a workout, Studio Zo is a space to reset, reconnect, and build a consistent routine that fits real life.</p>
        </div></Rv>
      </div>
    </section>

    <section id="method" style={{padding:"80px 24px",background:"var(--white)",borderTop:"1px solid var(--light-gray)"}}>
      <div style={{maxWidth:1000,margin:"0 auto"}}>
        <Rv><div style={{textAlign:"center",marginBottom:48}}><Eye>The Method</Eye><H2>Find your <span style={{fontStyle:"italic",color:"var(--nude)"}}>flow</span></H2></div></Rv>
        <div className="mc" style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:20}}>
          {[
            {n:"Zo Sculpt",d:"Signature heated Pilates focused on slow, controlled movement to lengthen, strengthen, and sculpt."},
            {n:"Zo Flow",d:"A dynamic, continuous flow combining Pilates with seamless transitions to build strength and elevate your heart rate."},
            {n:"Zo Method",d:"Classical Pilates rooted in precision and control. Foundational, focused, and form-driven."},
            {n:"Zo Restore",d:"A slower, restorative practice designed to stretch, release, and balance the intensity of your other classes."},
          ].map((c,i)=><Rv key={i} delay={i*.08}>
            <div style={{padding:"28px 24px",background:"var(--ivory)",borderLeft:"3px solid var(--nude)",borderRadius:"0 6px 6px 0"}}>
              <p style={{fontSize:".62rem",fontWeight:700,letterSpacing:".22em",color:"var(--nude)",marginBottom:8}}>{c.n.toUpperCase()}</p>
              <H2 sz="clamp(1.2rem,2.5vw,1.5rem)" style={{marginBottom:10}}>{c.n}</H2>
              <P style={{fontSize:".87rem"}}>{c.d}</P>
            </div>
          </Rv>)}
        </div>
      </div>
    </section>

    <section id="founder" style={{padding:"80px 24px",background:"var(--ivory)",borderTop:"1px solid var(--light-gray)"}}>
      <div className="mc" style={{maxWidth:1000,margin:"0 auto",display:"grid",gridTemplateColumns:"1fr 1.2fr",gap:48,alignItems:"center"}}>
        <Rv><img src="assets/Founder pic .JPG" alt="Zoya Burgess, Founder" style={{width:"100%",aspectRatio:"4/5",objectFit:"cover",borderRadius:6}}/></Rv>
        <Rv delay={.1}><div>
          <Eye>Founder</Eye>
          <H2 sz="clamp(1.7rem,3.5vw,2.4rem)" style={{marginBottom:16}}>Zoya Burgess</H2>
          <p style={{fontSize:".7rem",fontWeight:700,letterSpacing:".15em",color:"var(--nude)",marginBottom:18}}>FOUNDER, STUDIO ZO PILATES</p>
          <P style={{marginBottom:16}}>Studio Zo was created from a simple idea: your workout should be something you look forward to—not something you have to fit in. After years of practicing Pilates, Zoya struggled to find a space that felt both elevated and truly welcoming. She set out to create a studio that blends intentional movement with a refined, thoughtfully designed environment.</P>
          <P>Studio Zo was intentionally created in Northern Virginia—bringing a new standard of Pilates to the community Zoya calls home. The result is Northern Virginia's first infrared heated mat Pilates studio—built for real life. With elevated classes, a strong sense of community, and on-site childcare through Zo Kids, Studio Zo makes it easier to stay consistent without having to choose between fitness and everything else.</P>
        </div></Rv>
      </div>
    </section>

    <section id="differentiators" style={{padding:"80px 24px",background:"var(--white)",borderTop:"1px solid var(--light-gray)"}}>
      <div style={{maxWidth:1000,margin:"0 auto"}}>
        <Rv><div style={{textAlign:"center",marginBottom:48}}><Eye>What Sets Us Apart</Eye><H2>What makes Studio Zo <span style={{fontStyle:"italic",color:"var(--nude)"}}>different</span></H2></div></Rv>
        <div className="mc4" style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:16}}>
          {[
            {t:"Infrared Heated",d:"A deeper, more effective workout. Infrared heat supports muscle recovery while enhancing intensity and results."},
            {t:"On-Site Zo Kids",d:"Optional childcare, thoughtfully designed so you can fully focus on your workout."},
            {t:"Small Classes",d:"Intentional class sizes for personalized attention, hands-on guidance, and a more connected experience."},
            {t:"Elevated Space",d:"Warm, minimal design with refined details—created to feel calm, considered, and intentionally different."},
          ].map((v,i)=><Rv key={i} delay={i*.08}>
            <div style={{padding:"24px 20px",borderLeft:"2px solid var(--nude)",background:"var(--nude-bg)",borderRadius:"0 6px 6px 0",height:"100%"}}>
              <h4 style={{fontFamily:"var(--sans)",fontSize:".85rem",fontWeight:700,color:"var(--black)",marginBottom:8}}>{v.t}</h4>
              <P style={{fontSize:".82rem"}}>{v.d}</P>
            </div>
          </Rv>)}
        </div>
      </div>
    </section>

    {/* FAQ */}
    <section id="faq" style={{padding:"80px 24px",background:"var(--ivory)",borderTop:"1px solid var(--light-gray)"}}>
      <div style={{maxWidth:700,margin:"0 auto"}}>
        <Rv><div style={{textAlign:"center",marginBottom:40}}><Eye>FAQ</Eye><H2>Common <span style={{fontStyle:"italic",color:"var(--nude)"}}>questions</span></H2></div></Rv>
        {faqs.map((f,i)=><Rv key={i} delay={i*.04}>
          <button onClick={()=>setOpenFaq(openFaq===i?null:i)} style={{width:"100%",textAlign:"left",background:"none",border:"none",padding:"20px 0",borderBottom:"1px solid var(--light-gray)",display:"flex",justifyContent:"space-between",alignItems:"center",gap:16}}>
            <h4 style={{fontFamily:"var(--sans)",fontSize:".9rem",fontWeight:600,color:"var(--black)"}}>{f.q}</h4>
            <span style={{fontFamily:"var(--serif)",fontSize:"1.3rem",color:"var(--nude)",transform:openFaq===i?"rotate(45deg)":"rotate(0)",transition:"transform .3s",flexShrink:0}}>+</span>
          </button>
          {openFaq===i&&<div style={{padding:"12px 0 20px",animation:"fadeIn .25s ease-out"}}><P style={{fontSize:".85rem"}}>{f.a}</P></div>}
        </Rv>)}
      </div>
    </section>
  </div>
}

